#!/usr/bin/env python3

import os
import sys
import shutil
import subprocess
from pathlib import Path

ROOT = Path(__file__).resolve().parent
DIST_DIR = ROOT / "dist"
PACKAGE_NAME = ROOT.name
ARCHIVE_BASE = DIST_DIR / PACKAGE_NAME


def run(cmd, cwd=ROOT):
    print(f"+ {' '.join(cmd)}", flush=True)
    subprocess.run(cmd, cwd=cwd, check=True)


def ensure_requirements():
    req = ROOT / "requirements.txt"
    if not req.exists():
        print("requirements.txt not found", file=sys.stderr)
        sys.exit(1)
    return req


def install_dependencies(req):
    run([sys.executable, "-m", "pip", "install", "--disable-pip-version-check", "--no-input", "-r", str(req)])


def run_tests():
    if (ROOT / "pytest.ini").exists() or (ROOT / "pyproject.toml").exists() or (ROOT / "tests").exists():
        run([sys.executable, "-m", "pytest", "-q"])
    else:
        print("No test configuration found, skipping tests.", flush=True)


def clean_dist():
    if DIST_DIR.exists():
        shutil.rmtree(DIST_DIR)
    DIST_DIR.mkdir(parents=True, exist_ok=True)


def package():
    archive = shutil.make_archive(str(ARCHIVE_BASE), "zip", root_dir=ROOT)
    print(f"Created package: {archive}", flush=True)


def main():
    req = ensure_requirements()
    clean_dist()
    install_dependencies(req)
    run_tests()
    package()
    print("Deployment package ready.", flush=True)


if __name__ == "__main__":
    main()